import{_ as e,c as t,o as r,ae as p}from"./chunks/framework.Cd-3tpCq.js";const f=JSON.parse('{"title":"社区规则","description":"","frontmatter":{},"headers":[],"relativePath":"examplexd.md","filePath":"examplexd.md"}'),o={name:"examplexd.md"};function l(h,a,s,c,i,d){return r(),t("div",null,a[0]||(a[0]=[p('<h1 id="社区规则" tabindex="-1">社区规则 <a class="header-anchor" href="#社区规则" aria-label="Permalink to &quot;社区规则&quot;">​</a></h1><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">须知</p><p>此规定用于<a href="#">管理社区</a>，我们会逐步完善此规定，违反此规定者，我们管理组<a href="#">有权进行处罚</a>，<a href="#">最终解释权归服务器所有</a>，<a href="#">ratozi.top提供支持</a>。</p></div><h2 id="社区" tabindex="-1"><a href="/lx">社区</a> <a class="header-anchor" href="#社区" aria-label="Permalink to &quot;&lt;a href=&quot;/lx&quot;&gt;社区&lt;/a&gt;&quot;">​</a></h2><p>1.禁止发送涉政、色情、赌博、违反法律法规言论、讨论混的言论（以QQ官方所界定的类似 行为准则 等的文档为准）；禁止发布辱华、种族歧视、性别歧视等言论。</p><p>（<a href="/chf">点我查看处罚</a>）</p><p>2.不要说脏话（<a href="/chf">点我查看处罚</a>）；禁止辱骂管理员或群主。</p><p>管理员骂人是他的错，告诉群主即可。群友们不要跟着对骂噢。</p><p>如果对服务器有建议或是觉得管理组有方面做得不好，可以提出来，但不要直接开骂。不要提那种无端、无脑建议如 “建议把服务器IP改成 ratozi.top”。</p><p>惩罚.禁言2天。</p><p>3.禁止一直打电话骚扰（10分钟内打3次电话即可算为骚扰）。（<a href="/chf">点我查看处罚</a>）</p><p>4.群友可以在群里分享生活（如考试过了等），可以发照片，也可以发自己其它服务器打出来的精彩操作。（如内容违规，进行以下处罚）</p><p>惩罚.撤回内容，第一次警告，第二次禁言5天，第三次移出本群。</p><p>6.除上述内容以外，任何引人不适的内容、发言等都可能被惩罚。</p><p>惩罚.酌情处理。</p>',15)]))}const _=e(o,[["render",l]]);export{f as __pageData,_ as default};
